sql:
SELECT w.app_name, w.description, p.page_name, p.page_url
FROM web_applications w
JOIN pages p ON w.app_id = p.app_id;

SELECT app_name
FROM web_applications
WHERE app_name = 'specific_app_name';

SELECT session_id, app_id, ua_id, start_time, end_time, total_time, is_active
FROM sessions
WHERE session_id = 1;

SELECT app_name, app_url, description 
FROM web_applications 
WHERE app_id = 1;

external_knowledge:
- "shining stars" refers to web applications with high ratings; 
- "positive light" and "average glow" metaphorically represent user ratings;
- "threshold of 3 stars" indicates the minimum average rating considered high;
- "top 5 in the galaxy of high ratings" means selecting the top 5 applications based on average rating.

- 'App' at the end of a web application name signifies the application's identity as a software application; 
- The number of sessions a web application has reflects its engagement level; 
- The average interaction count is a metric representing the typical engagement level per session across all applications.
